import{_ as t,o as a,c as i,ae as l}from"./chunks/framework.Czhw_PXq.js";const p=JSON.parse('{"title":"Ultimate Monitoring & Observability Doctrine","description":"Mandatory visibility standards for agents, workflows, infrastructure, costs, and incidents across the OpenSIN fleet.","frontmatter":{"title":"Ultimate Monitoring & Observability Doctrine","description":"Mandatory visibility standards for agents, workflows, infrastructure, costs, and incidents across the OpenSIN fleet."},"headers":[],"relativePath":"best-practices/monitoring-observability.md","filePath":"best-practices/monitoring-observability.md"}'),r={name:"best-practices/monitoring-observability.md"};function s(o,e,n,d,c,h){return a(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="ultimate-monitoring-observability-doctrine" tabindex="-1">Ultimate Monitoring &amp; Observability Doctrine <a class="header-anchor" href="#ultimate-monitoring-observability-doctrine" aria-label="Permalink to &quot;Ultimate Monitoring &amp; Observability Doctrine&quot;">​</a></h1><blockquote><p><strong>RULE:</strong> If the fleet cannot see it, the fleet cannot trust it. Monitoring is not decoration. It is the nervous system of autonomous engineering.</p></blockquote><hr><h2 id="_1-core-principle" tabindex="-1">1. Core Principle <a class="header-anchor" href="#_1-core-principle" aria-label="Permalink to &quot;1. Core Principle&quot;">​</a></h2><p>Every significant system must answer these questions at all times:</p><ul><li>Is it alive?</li><li>Is it healthy?</li><li>Is it producing value?</li><li>Is it failing silently?</li><li>Is it costing too much?</li><li>Can we explain what happened after the fact?</li></ul><p>If a subsystem cannot answer these, it is not production-ready.</p><hr><h2 id="_2-observability-layers" tabindex="-1">2. Observability Layers <a class="header-anchor" href="#_2-observability-layers" aria-label="Permalink to &quot;2. Observability Layers&quot;">​</a></h2><h3 id="_2-1-agent-layer" tabindex="-1">2.1 Agent layer <a class="header-anchor" href="#_2-1-agent-layer" aria-label="Permalink to &quot;2.1 Agent layer&quot;">​</a></h3><p>Track:</p><ul><li>active sessions</li><li>error rate</li><li>response latency</li><li>model/tool availability</li><li>background task state</li><li>completion vs timeout vs cancellation</li></ul><h3 id="_2-2-workflow-layer" tabindex="-1">2.2 Workflow layer <a class="header-anchor" href="#_2-2-workflow-layer" aria-label="Permalink to &quot;2.2 Workflow layer&quot;">​</a></h3><p>Track:</p><ul><li>trigger frequency</li><li>execution success/failure</li><li>queue backlogs</li><li>node-level bottlenecks</li><li>side effect confirmation</li></ul><h3 id="_2-3-infrastructure-layer" tabindex="-1">2.3 Infrastructure layer <a class="header-anchor" href="#_2-3-infrastructure-layer" aria-label="Permalink to &quot;2.3 Infrastructure layer&quot;">​</a></h3><p>Track:</p><ul><li>CPU / memory / disk</li><li>network health</li><li>storage exhaustion risk</li><li>process uptime</li><li>HF Space sleep/restart behavior</li></ul><h3 id="_2-4-economic-layer" tabindex="-1">2.4 Economic layer <a class="header-anchor" href="#_2-4-economic-layer" aria-label="Permalink to &quot;2.4 Economic layer&quot;">​</a></h3><p>Track:</p><ul><li>token usage</li><li>hourly cost</li><li>cost spikes per workflow / agent / model</li><li>expensive retry loops</li></ul><hr><h2 id="_3-mandatory-health-checks" tabindex="-1">3. Mandatory Health Checks <a class="header-anchor" href="#_3-mandatory-health-checks" aria-label="Permalink to &quot;3. Mandatory Health Checks&quot;">​</a></h2><p>Every production-capable component needs a health signal:</p><ul><li>websites → reachable URL / status check</li><li>APIs → health endpoint or equivalent request</li><li>workflows → last successful execution timestamp</li><li>agents → last heartbeat / last activity</li><li>MCP tools → list-tools / smoke-call success</li></ul><h3 id="why" tabindex="-1">Why <a class="header-anchor" href="#why" aria-label="Permalink to &quot;Why&quot;">​</a></h3><p>A component that is “probably fine” is already a liability.</p><hr><h2 id="_4-logging-rules" tabindex="-1">4. Logging Rules <a class="header-anchor" href="#_4-logging-rules" aria-label="Permalink to &quot;4. Logging Rules&quot;">​</a></h2><h3 id="_4-1-structured-logs-only-where-possible" tabindex="-1">4.1 Structured logs only where possible <a class="header-anchor" href="#_4-1-structured-logs-only-where-possible" aria-label="Permalink to &quot;4.1 Structured logs only where possible&quot;">​</a></h3><p>Prefer machine-readable logs with fields for:</p><ul><li>timestamp</li><li>component</li><li>severity</li><li>session/task/issue IDs</li><li>action</li><li>result</li><li>error class</li></ul><h3 id="_4-2-redaction-is-mandatory" tabindex="-1">4.2 Redaction is mandatory <a class="header-anchor" href="#_4-2-redaction-is-mandatory" aria-label="Permalink to &quot;4.2 Redaction is mandatory&quot;">​</a></h3><p>Never log raw secrets, tokens, passwords, or credentials. Log references, not secrets.</p><h3 id="_4-3-log-what-matters" tabindex="-1">4.3 Log what matters <a class="header-anchor" href="#_4-3-log-what-matters" aria-label="Permalink to &quot;4.3 Log what matters&quot;">​</a></h3><p>Log:</p><ul><li>starts</li><li>finishes</li><li>retries</li><li>failures</li><li>unusual paths</li><li>external side effects Do <strong>not</strong> drown the system in meaningless noise.</li></ul><hr><h2 id="_5-alerting-rules" tabindex="-1">5. Alerting Rules <a class="header-anchor" href="#_5-alerting-rules" aria-label="Permalink to &quot;5. Alerting Rules&quot;">​</a></h2><p>Alert only on things that require action.</p><h3 id="critical-alerts" tabindex="-1">Critical alerts <a class="header-anchor" href="#critical-alerts" aria-label="Permalink to &quot;Critical alerts&quot;">​</a></h3><ul><li>system down</li><li>auth broken</li><li>workflow repeatedly failing</li><li>data loss risk</li><li>billing/cost anomaly</li><li>stuck queue / stuck retry loop</li></ul><h3 id="warning-alerts" tabindex="-1">Warning alerts <a class="header-anchor" href="#warning-alerts" aria-label="Permalink to &quot;Warning alerts&quot;">​</a></h3><ul><li>degraded latency</li><li>elevated error rate</li><li>stale worker</li><li>missed execution window</li></ul><h3 id="anti-pattern" tabindex="-1">Anti-pattern <a class="header-anchor" href="#anti-pattern" aria-label="Permalink to &quot;Anti-pattern&quot;">​</a></h3><p>Do not send alerts for every minor fluctuation. Alert fatigue blinds operators.</p><hr><h2 id="_6-evidence-preservation" tabindex="-1">6. Evidence Preservation <a class="header-anchor" href="#_6-evidence-preservation" aria-label="Permalink to &quot;6. Evidence Preservation&quot;">​</a></h2><p>Important incidents must preserve evidence:</p><ul><li>screenshots</li><li>logs</li><li>failing payloads</li><li>URLs</li><li>execution IDs</li><li>commit/branch/issue references</li></ul><p>Where LogCenter applies, upload there. <code>/tmp</code> is temporary, not authoritative.</p><hr><h2 id="_7-dashboards-must-be-operationally-useful" tabindex="-1">7. Dashboards Must Be Operationally Useful <a class="header-anchor" href="#_7-dashboards-must-be-operationally-useful" aria-label="Permalink to &quot;7. Dashboards Must Be Operationally Useful&quot;">​</a></h2><p>A good dashboard tells the operator what to do next. A bad dashboard is just colorful guilt.</p><p>Minimum useful dashboard sections:</p><ul><li>overall fleet health</li><li>current incidents</li><li>recent failed executions</li><li>hot repos / open blockers</li><li>cost trends</li><li>deployment state</li></ul><hr><h2 id="_8-cost-observability" tabindex="-1">8. Cost Observability <a class="header-anchor" href="#_8-cost-observability" aria-label="Permalink to &quot;8. Cost Observability&quot;">​</a></h2><p>The fleet must watch for:</p><ul><li>runaway retries</li><li>bad model routing</li><li>needlessly expensive model selection</li><li>repeated failed background tasks</li><li>duplicate agents doing the same work</li></ul><h3 id="why-1" tabindex="-1">Why <a class="header-anchor" href="#why-1" aria-label="Permalink to &quot;Why&quot;">​</a></h3><p>An autonomous system that does not watch cost becomes a denial-of-wallet attack against itself.</p><hr><h2 id="_9-silent-failure-prevention" tabindex="-1">9. Silent Failure Prevention <a class="header-anchor" href="#_9-silent-failure-prevention" aria-label="Permalink to &quot;9. Silent Failure Prevention&quot;">​</a></h2><p>Every important side effect must be checked downstream. Examples:</p><ul><li>issue supposedly created → confirm issue URL exists</li><li>blog supposedly published → confirm file exists and page resolves</li><li>deploy supposedly finished → confirm URL and assets load</li><li>agent supposedly completed → confirm result retrievable</li></ul><p>Do not trust intermediate success messages over final reality.</p><hr><h2 id="_10-suggested-standard-metrics" tabindex="-1">10. Suggested Standard Metrics <a class="header-anchor" href="#_10-suggested-standard-metrics" aria-label="Permalink to &quot;10. Suggested Standard Metrics&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Area</th><th>Metric</th><th>Why it matters</th></tr></thead><tbody><tr><td>Agents</td><td>active sessions</td><td>detects stalls and overload</td></tr><tr><td>Agents</td><td>error rate</td><td>reveals instability</td></tr><tr><td>Agents</td><td>avg / p95 latency</td><td>reveals slowdowns</td></tr><tr><td>Workflows</td><td>success rate</td><td>proves automation health</td></tr><tr><td>Workflows</td><td>execution age</td><td>detects dead pipelines</td></tr><tr><td>Infra</td><td>memory / disk</td><td>prevents crashes</td></tr><tr><td>Costs</td><td>hourly spend</td><td>prevents runaway economics</td></tr><tr><td>Product</td><td>live URL health</td><td>proves end-user reality</td></tr></tbody></table><hr><h2 id="_11-final-rule" tabindex="-1">11. Final Rule <a class="header-anchor" href="#_11-final-rule" aria-label="Permalink to &quot;11. Final Rule&quot;">​</a></h2><p><strong>Monitoring is not for feeling informed. It is for enabling intervention.</strong> If a metric cannot drive a decision, rethink why you are collecting it.</p><hr><p><em>Last updated:</em> 2026-04-10<br><em>Status:</em> <strong>ACTIVE &amp; MANDATORY</strong><br><em>Maintainer:</em> sin-zeus</p>',75)])])}const b=t(r,[["render",s]]);export{p as __pageData,b as default};
